// Use n8n's built-in $now which respects the n8n instance timezone
// Set your timezone in n8n Settings > General > Timezone
const now = new Date();

// Convert to your business timezone without luxon
const formatter = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/New_York', // Change to your timezone
  weekday: 'short',
  hour: 'numeric',
  hour12: false
});

const parts = formatter.formatToParts(now);
const weekday = parts.find(p => p.type === 'weekday').value; // 'Mon', 'Tue', etc.
const hour = parseInt(parts.find(p => p.type === 'hour').value);

const isWeekday = !['Sat', 'Sun'].includes(weekday);
const isWorkingHour = hour >= 9 && hour < 17;

return {
  isBusinessHours: isWeekday && isWorkingHour
};
